patch:
--- a/multiplexer.v
+++ b/multiplexer.v
@@ -8,7 +8,7 @@
   output [7:0] data_out
 );

-  always @(sel)
+  always @(sel or in0 or in1 or in2 or in3)
   begin
     case(sel)
       2'b00: data_out = in0;

before_code:
module multiplexer_8bit (
  input [7:0] in0, in1, in2, in3,
  input [1:0] sel,
  output [7:0] data_out
);

  always @(sel)
  begin
    case(sel)
      2'b00: data_out = in0;
      2'b01: data_out = in1;
      2'b10: data_out = in2;
      2'b11: data_out = in3;
      default: data_out = 8'h00;
    endcase
  end

endmodule

after_code:
module multiplexer_8bit (
  input [7:0] in0, in1, in2, in3,
  input [1:0] sel,
  output [7:0] data_out
);

  always @(sel or in0 or in1 or in2 or in3)
  begin
    case(sel)
      2'b00: data_out = in0;
      2'b01: data_out = in1;
      2'b10: data_out = in2;
      2'b11: data_out = in3;
      default: data_out = 8'h00;
    endcase
  end

endmodule
